Assignment Answer:
SELECT
   CONCAT(store_name, ' (', state, ')') AS Store_list, email
FROM stores;

Practice Answer:
SELECT email
FROM stores
ORDER BY email DESC;

Assignment Answer:
SELECT brand_name
FROM brands
ORDER BY brand_name;

Practice Answer:
SELECT first_name, last_name
FROM staffs
ORDER BY first_name;

Assignment Answer:
SELECT product_name, model_year
FROM products
ORDER BY model_year desc;

Practice Answer:
SELECT store_name AS Store, phone AS Tel
FROM stores
ORDER BY state DESC, city;

Assignment Answer:
SELECT product_name AS Product, list_price AS Price
FROM products
ORDER BY list_price DESC;
